mapper.select:
SELECT * FROM ( SELECT p.PRODUCTNO as productNo, p.PRODUCTNAME as productName, p.PRODUCTTYPE as productType, p.CATEGORYID as categoryId, c.CATEGORYNAME as categoryName, p.DESCRIPTION as description, p.BASERATE as baseRate, p.MATURITYRATE as maturityRate, p.EARLYTERMINATERATE as earlyTerminateRate, p.MONTHLYAMOUNT as monthlyAmount, p.SAVINGTERM as savingTerm, p.DEPOSITAMOUNT as depositAmount, p.INTERESTMETHOD as interestMethod, p.PAYCYCLE as payCycle, TO_CHAR(p.ENDDATE, 'YYYY-MM-DD') as endDate, p.ADMINID as adminId, TO_CHAR(p.CREATEDAT, 'YYYY-MM-DD HH24:MI:SS') as createdAt, TO_CHAR(p.UPDATEDAT, 'YYYY-MM-DD HH24:MI:SS') as updatedAt, p.STATUS as status, ROW_NUMBER() OVER (ORDER BY p.createdAt DESC) as rnum FROM PRODUCT p LEFT JOIN CATEGORY c ON p.CATEGORYID = c.CATEGORYID WHERE p.status = 'Y'
AND ( p.productName LIKE '%' || #{searchKeyword} || '%' OR p.description LIKE '%' || #{searchKeyword} || '%' )
AND p.productType = #{productType}
) WHERE rnum BETWEEN #{offset} + 1 AND #{offset} + #{limit}

SELECT COUNT(*) FROM PRODUCT WHERE status = 'Y'
AND ( productName LIKE '%' || #{searchKeyword} || '%' OR description LIKE '%' || #{searchKeyword} || '%' )
AND productType = #{productType}

mapper.update:
